/*
 * pill_dispenser.ino — Automated Pill Dispenser
 *
 * Elements:
 *   1. DS3231 RTC Alarm         — fires at each programmed dose time
 *   2. NEMA17 + DRV8825 Stepper — advances 7-compartment carousel
 *   3. SSD1306 OLED             — live display
 *   4. Arduino Nano             — orchestrator
 *
 * Wiring:
 *   DS3231 INT → D3 (INT1)
 *   DRV8825 STEP → D8, DIR → D9, ENABLE → D10 (active LOW)
 *   HX711 CLK → D4, DOUT → D5  (load cell, optional confirmation)
 *   Buzzer → D7
 */

#include <Wire.h>
#include <RTClib.h>
#include <AccelStepper.h>
#include <Adafruit_SSD1306.h>

// --- Config ---
#define COMPARTMENTS        7
#define STEPS_PER_REV     200
#define STEPS_PER_SLOT    (STEPS_PER_REV / COMPARTMENTS)  // 28 (full-step)
#define BUZZ_PIN            7
#define STEP_PIN            8
#define DIR_PIN             9
#define EN_PIN             10
#define RTC_INT_PIN         3
#define BUZZ_DURATION_MS 60000UL

// --- Globals ---
RTC_DS3231          rtc;
AccelStepper        stepper(AccelStepper::DRIVER, STEP_PIN, DIR_PIN);
Adafruit_SSD1306    oled(128, 64, &Wire, -1);

uint8_t  current_slot      = 0;
volatile bool dose_due     = false;
unsigned long buzz_start   = 0;
bool    buzzing            = false;

void on_rtc_alarm() { dose_due = true; }

void update_oled(DateTime& next) {
  oled.clearDisplay();
  oled.setTextSize(1);
  oled.setTextColor(SSD1306_WHITE);
  oled.setCursor(0, 0);
  oled.print(F("Pill Dispenser"));
  oled.setCursor(0, 16);
  oled.printf("Slot: %d/%d", current_slot + 1, COMPARTMENTS);
  oled.setCursor(0, 32);
  oled.printf("Next: %02d:%02d", next.hour(), next.minute());
  oled.display();
}

void advance_carousel() {
  long target = stepper.currentPosition() + STEPS_PER_SLOT;
  stepper.moveTo(target);
  while (stepper.distanceToGo() != 0) stepper.run();
  current_slot = (current_slot + 1) % COMPARTMENTS;
  Serial.printf("Dispensed slot %d at ", current_slot);
  DateTime now = rtc.now();
  Serial.printf("%02d:%02d\n", now.hour(), now.minute());
}

void setup() {
  Serial.begin(115200);
  Wire.begin();

  rtc.begin();
  rtc.clearAlarm(1); rtc.clearAlarm(2);

  // Example: dose at 08:00 and 20:00 (set alarm 1 = 08:00)
  rtc.setAlarm1(DateTime(0,0,0,8,0,0), DS3231_A1_Hour);
  rtc.writeSqwPinMode(DS3231_OFF);

  stepper.setMaxSpeed(300);
  stepper.setAcceleration(150);
  stepper.setCurrentPosition(0);
  pinMode(EN_PIN, OUTPUT);
  digitalWrite(EN_PIN, LOW);  // enable driver

  oled.begin(SSD1306_SWITCHCAPVCC, 0x3C);
  oled.clearDisplay(); oled.display();

  pinMode(BUZZ_PIN, OUTPUT); digitalWrite(BUZZ_PIN, LOW);
  pinMode(RTC_INT_PIN, INPUT_PULLUP);
  attachInterrupt(digitalPinToInterrupt(RTC_INT_PIN), on_rtc_alarm, FALLING);

  Serial.println(F("Pill dispenser ready."));
}

void loop() {
  static unsigned long last_disp = 0;

  // --- 1. Stepper running ---
  stepper.run();

  // --- 2. Dispense on alarm ---
  if (dose_due) {
    dose_due = false;
    rtc.clearAlarm(1);
    advance_carousel();
    // Start buzzer to notify user
    buzz_start = millis();
    buzzing    = true;
    digitalWrite(BUZZ_PIN, HIGH);
  }

  // --- 3. Buzzer timeout ---
  if (buzzing && (millis() - buzz_start >= BUZZ_DURATION_MS)) {
    buzzing = false;
    digitalWrite(BUZZ_PIN, LOW);
  }

  // --- 4. OLED refresh ---
  if (millis() - last_disp >= 2000UL) {
    last_disp = millis();
    DateTime next_dose(0,0,0,8,0,0);  // placeholder — read from EEPROM in full implementation
    update_oled(next_dose);
  }
}
